import java.io.File;
import java.util.HashMap;
import java.util.Map;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.xpath.XPathConstants;
import javax.xml.xpath.XPathExpressionException;
import javax.xml.xpath.XPathFactory;

public class XMLParser {
    public static Map<String, String> parseXML(File xmlFile) throws Exception {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setValidating(false);
        dbf.setNamespaceAware(true);
        DocumentBuilder db = dbf.newDocumentBuilder();
        org.w3c.dom.Document doc = db.parse(xmlFile);

        XPathFactory xpf = XPathFactory.newInstance();
        XPathExpression expr = xpf.compile("//configuration/setting");
        NodeList nodes = (NodeList) expr.evaluate(doc, XPathConstants.NODESET);

        Map<String, String> configSettings = new HashMap<>();
        for (int i = 0; i < nodes.getLength(); i++) {
            Node node = nodes.item(i);
            String key = node.getAttributes().getNamedItem("key").getTextContent();
            String value = node.getAttributes().getNamedItem("value").getTextContent();
            configSettings.put(key, value);
        }

        return configSettings;
    }
}